const Complaint = require('../models/Complaint');
const Notification = require('../models/Notification');
const User = require('../models/User');

// Helper to send socket notification
const notifyUser = async (req, userId, message) => {
  const notification = await Notification.create({ user: userId, message });
  req.io.to(userId.toString()).emit('notification', notification);
};

// @desc    Create a new complaint
// @route   POST /api/complaints
// @access  Private
const createComplaint = async (req, res) => {
  const { description, lat, lng, address, priority } = req.body;
  const image = req.file ? `/uploads/${req.file.filename}` : null;

  if (!image || !lat || !lng) {
    return res.status(400).json({ message: 'Missing fields' });
  }

  const complaint = await Complaint.create({
    user: req.user._id,
    image,
    description,
    location: { lat, lng, address },
    priority: priority || 'Normal'
  });

  // Notify Admins
  const admins = await User.find({ role: 'Admin' });
  admins.forEach(admin => {
    notifyUser(req, admin._id, 'A new complaint has been filed.');
  });

  res.status(201).json(complaint);
};

// @desc    Get all complaints (Admin) or User's own complaints
// @route   GET /api/complaints
// @access  Private
const getComplaints = async (req, res) => {
  let query = {};
  if (req.user.role === 'User') {
    query.user = req.user._id;
  } else if (req.user.role === 'Sweeper') {
    query.assignedTo = req.user._id;
  }

  const complaints = await Complaint.find(query).populate('user', 'name email').populate('assignedTo', 'name');
  res.json(complaints);
};

// @desc    Assign Sweeper to Complaint
// @route   PUT /api/complaints/:id/assign
// @access  Admin
const assignSweeper = async (req, res) => {
  const { sweeperId } = req.body;
  
  const complaint = await Complaint.findById(req.params.id);

  if (complaint) {
    complaint.assignedTo = sweeperId;
    complaint.status = 'In Progress';
    const updatedComplaint = await complaint.save();

    // Notify the Sweeper
    notifyUser(req, sweeperId, `You have been assigned a new task: ${complaint.description}`);
    // Notify the User
    notifyUser(req, complaint.user, 'Your complaint check is in progress. A sweeper is assigned.');

    res.json(updatedComplaint);
  } else {
    res.status(404).json({ message: 'Complaint not found' });
  }
};

// @desc    Update complaint status (Sweeper marking complete with proof)
// @route   PUT /api/complaints/:id/status
// @access  Private
const updateStatus = async (req, res) => {
  const complaint = await Complaint.findById(req.params.id);

  if (complaint) {
    complaint.status = req.body.status || complaint.status;

    if (req.body.status === 'Completed' && req.file) {
       complaint.afterImage = `/uploads/${req.file.filename}`;
    }

    const updatedComplaint = await complaint.save();

    // Notify User
    if (complaint.status === 'Completed') {
      notifyUser(req, complaint.user, 'Your complaint has been successfully resolved!');
      // Also notify Admins
      const admins = await User.find({ role: 'Admin' });
      admins.forEach(admin => {
        notifyUser(req, admin._id, `Task Completed: Complaint ${complaint._id.toString().substring(0,6)} is clean!`);
      });
    }

    res.json(updatedComplaint);
  } else {
    res.status(404).json({ message: 'Complaint not found' });
  }
};

// @desc    Get Admin Analytics
// @route   GET /api/complaints/analytics
// @access  Admin
const getAnalytics = async (req, res) => {
  const total = await Complaint.countDocuments();
  const pending = await Complaint.countDocuments({ status: 'Pending' });
  const inProgress = await Complaint.countDocuments({ status: 'In Progress' });
  const completed = await Complaint.countDocuments({ status: 'Completed' });

  res.json({ total, pending, inProgress, completed });
};

// @desc   Get sweepers list for assignment
// @route  GET /api/complaints/sweepers
// @access Admin
const getSweepers = async (req, res) => {
  const sweepers = await User.find({ role: 'Sweeper' }).select('-password');
  res.json(sweepers);
};

module.exports = {
  createComplaint,
  getComplaints,
  assignSweeper,
  updateStatus,
  getAnalytics,
  getSweepers
};
